// ═══════════════════════════════════════════════════════════════
// STRUCTURATION DES DONNÉES STC PAR DESTINATAIRE ET NIVEAU
// Niveaux : SALARIE / SUPERIEUR / FARHAT / BAALLAH / DGA / PDG
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION DES NOTIFICATIONS - STC');
console.log('═══════════════════════════════════════════════════');
console.log(`STC reçus: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const data = item.json;

  let destinatairePrincipal;
  let codeDestinataire;
  let typeDestinataire;

  if (data.niveau_escalade === 'PDG') {
    destinatairePrincipal = {
      code:      data.code_pdg,
      nom:       data.nom_pdg,
      prenom:    data.prenom_pdg,
      email:     data.email_pdg,
      telephone: data.telephone_pdg,
      chat_id:   data.chat_id_pdg,
      langue:    data.langue_pdg || 'FRA',
      bot:       data.bot_pdg
    };
    codeDestinataire = data.code_pdg;
    typeDestinataire = 'PDG';

  } else if (data.niveau_escalade === 'DGA') {
    destinatairePrincipal = {
      code:      data.code_dga,
      nom:       data.nom_dga,
      prenom:    data.prenom_dga,
      email:     data.email_dga,
      telephone: data.telephone_dga,
      chat_id:   data.chat_id_dga,
      langue:    data.langue_dga || 'FRA',
      bot:       data.bot_dga
    };
    codeDestinataire = data.code_dga;
    typeDestinataire = 'DGA';

  } else if (data.niveau_escalade === 'BAALLAH') {
    destinatairePrincipal = {
      code:      data.code_baallah,
      nom:       data.nom_baallah,
      prenom:    data.prenom_baallah,
      email:     data.email_baallah,
      telephone: data.telephone_baallah,
      chat_id:   data.chat_id_baallah,
      langue:    data.langue_baallah || 'FRA',
      bot:       data.bot_baallah
    };
    codeDestinataire = data.code_baallah;
    typeDestinataire = 'BAALLAH';

  } else if (data.niveau_escalade === 'FARHAT') {
    destinatairePrincipal = {
      code:      data.code_farhat,
      nom:       data.nom_farhat,
      prenom:    data.prenom_farhat,
      email:     data.email_farhat || null,
      telephone: data.telephone_farhat || null,
      chat_id:   data.chat_id_farhat || null,
      langue:    data.langue_farhat || 'FRA',
      bot:       data.bot_farhat || null
    };
    codeDestinataire = data.code_farhat;
    typeDestinataire = 'FARHAT';

  } else if (data.niveau_escalade === 'SUPERIEUR') {
    destinatairePrincipal = {
      code:      data.code_superieur,
      nom:       data.nom_superieur,
      prenom:    data.prenom_superieur,
      email:     data.email_superieur,
      telephone: data.tel_superieur,
      chat_id:   data.chat_id_superieur,
      langue:    data.langue_superieur || 'FRA',
      bot:       data.bot_superieur
    };
    codeDestinataire = data.code_superieur;
    typeDestinataire = 'SUPERIEUR';

  } else if (data.niveau_escalade === 'SALARIE') {
    destinatairePrincipal = {
      code:      data.code_salarie,
      nom:       data.nom_salarie,
      prenom:    '',
      email:     data.email_salarie,
      telephone: data.tel_salarie,
      chat_id:   data.chat_id_salarie,
      langue:    data.langue_salarie || 'FRA',
      bot:       data.bot_salarie
    };
    codeDestinataire = data.code_salarie;
    typeDestinataire = 'SALARIE';

  } else {
    console.log(`⏭️  STC ${data.numero_stc} ignoré (niveau: ${data.niveau_escalade})`);
    return;
  }

  const cleDestinataire = `${typeDestinataire}_${codeDestinataire}`;

  if (!notifications[cleDestinataire]) {
    notifications[cleDestinataire] = {
      destinataire_principal: destinatairePrincipal,
      type_destinataire:      typeDestinataire,
      niveau_escalade:        data.niveau_escalade,

      salarie: {
        code:      data.code_salarie,
        nom:       data.nom_salarie,
        email:     data.email_salarie,
        telephone: data.tel_salarie,
        chat_id:   data.chat_id_salarie,
        langue:    data.langue_salarie || 'FRA',
        bot:       data.bot_salarie
      },
      superieur: {
        code:      data.code_superieur,
        nom:       data.nom_superieur,
        prenom:    data.prenom_superieur,
        email:     data.email_superieur,
        telephone: data.tel_superieur,
        chat_id:   data.chat_id_superieur,
        langue:    data.langue_superieur || 'FRA',
        bot:       data.bot_superieur
      },
      pdg: {
        code:      data.code_pdg,
        nom:       data.nom_pdg,
        prenom:    data.prenom_pdg,
        email:     data.email_pdg,
        telephone: data.telephone_pdg,
        chat_id:   data.chat_id_pdg,
        langue:    data.langue_pdg || 'FRA',
        bot:       data.bot_pdg
      },
      dga: {
        code:      data.code_dga,
        nom:       data.nom_dga,
        prenom:    data.prenom_dga,
        email:     data.email_dga,
        telephone: data.telephone_dga,
        chat_id:   data.chat_id_dga,
        langue:    data.langue_dga || 'FRA',
        bot:       data.bot_dga
      },
      farhat: {
        code:      data.code_farhat,
        nom:       data.nom_farhat,
        prenom:    data.prenom_farhat,
        email:     data.email_farhat,
        telephone: data.telephone_farhat,
        chat_id:   data.chat_id_farhat,
        langue:    data.langue_farhat || 'FRA',
        bot:       data.bot_farhat
      },
      baallah: {
        code:      data.code_baallah,
        nom:       data.nom_baallah,
        prenom:    data.prenom_baallah,
        email:     data.email_baallah,
        telephone: data.telephone_baallah,
        chat_id:   data.chat_id_baallah,
        langue:    data.langue_baallah || 'FRA',
        bot:       data.bot_baallah
      },

      stc_list: []
    };
  }

  notifications[cleDestinataire].stc_list.push({
    numero_stc:            data.numero_stc,
    date_demande:          data.date_demande,
    date_creation:         data.date_creation,
    utilisateur_createur:  data.utilisateur_createur,
    code_salarie:          data.code_salarie,
    nom_salarie:           data.nom_salarie,
    poste:                 data.poste,
    salaire_base:          data.salaire_base,
    net_payer:             data.net_payer,
    delai_int:             data.delai_int,
    seuil_dga:             data.seuil_dga,
    date_limite:           data.date_limite,
    jours_depuis_creation: data.jours_depuis_creation,
    jours_restants:        data.jours_restants
  });
});

const resultats = Object.values(notifications).map(notif => {
  const joursMin   = Math.min(...notif.stc_list.map(s => s.jours_restants));
  const joursMax   = Math.max(...notif.stc_list.map(s => s.jours_restants));
  const delaiTotal = parseInt(notif.stc_list[0]?.delai_int) || 10;
  const seuilDga   = Math.floor(delaiTotal / 2);

  let emailCC   = [];
  let chatIDsCC = [];

  if (notif.type_destinataire === 'PDG') {
    if (notif.superieur.email)   emailCC.push(notif.superieur.email);
    if (notif.salarie.email)     emailCC.push(notif.salarie.email);
    if (notif.superieur.chat_id) chatIDsCC.push({ chat_id: notif.superieur.chat_id, bot: notif.superieur.bot, langue: notif.superieur.langue, nom: notif.superieur.nom });
    if (notif.salarie.chat_id)   chatIDsCC.push({ chat_id: notif.salarie.chat_id,   bot: notif.salarie.bot,   langue: notif.salarie.langue,   nom: notif.salarie.nom });

  } else if (notif.type_destinataire === 'SUPERIEUR') {
    if (notif.salarie.email)   emailCC.push(notif.salarie.email);
    if (notif.salarie.chat_id) chatIDsCC.push({ chat_id: notif.salarie.chat_id, bot: notif.salarie.bot, langue: notif.salarie.langue, nom: notif.salarie.nom });
  }
  // DGA, BAALLAH, FARHAT, SALARIE → pas de CC

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire:      notif.type_destinataire,
    niveau_escalade:        notif.niveau_escalade,
    email_cc:               emailCC.length   > 0 ? emailCC.join(',') : null,
    telegram_cc:            chatIDsCC.length > 0 ? chatIDsCC         : null,
    salarie:   notif.salarie,
    superieur: notif.superieur,
    pdg:       notif.pdg,
    dga:       notif.dga,
    farhat:    notif.farhat,
    baallah:   notif.baallah,
    stc_list:  notif.stc_list,
    statistiques: {
      total_stc:   notif.stc_list.length,
      jours_min:   joursMin,
      jours_max:   joursMax,
      priorite:    notif.niveau_escalade,
      delai_total: delaiTotal,
      seuil_dga:   seuilDga
    },
    meta: {
      date_traitement:       new Date().toISOString(),
      langue_message:        notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email:    !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id
    }
  };
});

console.log(`\n✅ Notifications structurées: ${resultats.length}`);
console.log('Par type:');
['PDG','DGA','BAALLAH','FARHAT','SUPERIEUR','SALARIE'].forEach(t => {
  const n = resultats.filter(r => r.type_destinataire === t).length;
  if (n > 0) console.log(`  - ${t}: ${n}`);
});
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

