function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleDateString(locale, { year: 'numeric', month: '2-digit', day: '2-digit' });
  } catch(e) { return dateStr; }
}

function formaterNombre(n) {
  if (n == null) return 'N/A';
  return Number(n).toLocaleString('fr-FR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function getEmoji(jours) {
  if (jours <= 1) return '🔴';
  if (jours <= 3) return '🟠';
  if (jours <= 5) return '🟡';
  return '🔵';
}

function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const dest = data.destinataire_principal;
  const stats = data.statistiques;
  const stcList = data.stc_list;
  const type = data.type_destinataire;

  let emailSubject = (T.sujet_email[type] || T.sujet_email.SALARIE) + ` - ${stats.total_stc} STC`;

  let emailBody = `${T.salutation} ${dest.prenom ? dest.prenom + ' ' : ''}${dest.nom},\n\n`;
  emailBody += `${T.introduction[type]}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau d'escalade: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_stc}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;
  emailBody += `${T.delai_total}: ${stats.delai_total} ${T.jours}\n`;
  if (['DGA','BAALLAH'].includes(type)) {
    emailBody += `${T.seuil_dga}: ${stats.seuil_dga} ${T.jours}\n`;
  }
  emailBody += `\n═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_liste}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  stcList.forEach((stc, index) => {
    emailBody += `${index + 1}. ${getEmoji(stc.jours_restants)} ${stc.numero_stc}\n`;
    emailBody += `   📅 ${T.date_demande}: ${formaterDate(stc.date_demande, langue)}\n`;
    emailBody += `   🧑 ${T.salarie}: ${stc.nom_salarie} (${stc.code_salarie})\n`;
    if (stc.poste)        emailBody += `   💼 ${T.poste}: ${stc.poste}\n`;
    if (stc.salaire_base) emailBody += `   💰 ${T.salaire}: ${formaterNombre(stc.salaire_base)} MAD\n`;
    if (stc.net_payer)    emailBody += `   💵 ${T.net}: ${formaterNombre(stc.net_payer)} MAD\n`;
    emailBody += `   ⏰ ${T.restant}: ${stc.jours_restants} ${T.jours} (${T.limite}: ${formaterDate(stc.date_limite, langue)})\n`;
    if (stc.jours_restants <= 1) emailBody += `   🚨 ${T.urgent}\n`;
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📌 ${T.action}: ${T.instruction[type]}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${T.cordialement},\n\n${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  emailBody += `${T.ne_pas_repondre}\n`;

  // ── Telegram ──
  let telegram = `${getEmoji(stats.jours_min)} *${T.sujet_email[type]}*\n`;
  telegram += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegram += `👤 *${dest.prenom ? dest.prenom + ' ' : ''}${dest.nom}*\n\n`;
  telegram += `📊 *${T.section_stats}*\n`;
  telegram += `${T.total}: *${stats.total_stc}*\n`;
  telegram += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;
  telegram += `📋 *${T.section_liste}*\n\n`;
  stcList.slice(0, 5).forEach((stc, index) => {
    telegram += `${index + 1}. ${getEmoji(stc.jours_restants)} *${stc.numero_stc}*\n`;
    telegram += `   📅 ${formaterDate(stc.date_demande, langue)}\n`;
    telegram += `   🧑 ${stc.nom_salarie}\n`;
    telegram += `   ⏰ ${stc.jours_restants} ${T.jours}\n\n`;
  });
  if (stcList.length > 5) telegram += `... et ${stcList.length - 5} autre(s) STC\n\n`;
  if (stats.jours_min <= 1) telegram += `🚨 *${T.urgent}*\n\n`;

  return {
    email:    { subject: emailSubject, body: emailBody },
    telegram: { text: telegram, parse_mode: 'Markdown' }
  };
}

function genererMessageCC(data, destinataireCC, typeDestinatairePrincipal) {
  const langue = destinataireCC.langue || data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const stats = data.statistiques;
  const stcList = data.stc_list;
  const destPrincipal = data.destinataire_principal;

  const labels = {
    SUPERIEUR: T.cc_message.votre_superieur,
    PDG:       T.cc_message.le_pdg,
    DGA:       T.cc_message.le_dga,
    FARHAT:    T.cc_message.le_farhat,
    BAALLAH:   T.cc_message.le_baallah
  };
  const label = labels[typeDestinatairePrincipal] || typeDestinatairePrincipal;

  let emailSubject = `${T.copie_info} - ${T.sujet_email[typeDestinatairePrincipal]} - ${stats.total_stc} STC`;

  let emailBody = `${T.salutation} ${destinataireCC.prenom ? destinataireCC.prenom + ' ' : ''}${destinataireCC.nom},\n\n`;
  emailBody += `${T.cc_message.base} ${label} ${destPrincipal.prenom || ''} ${destPrincipal.nom}.\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade} | ${T.total}: ${stats.total_stc} | ${T.delai_min}: ${stats.jours_min} ${T.jours}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_liste}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  stcList.forEach((stc, index) => {
    emailBody += `${index + 1}. ${getEmoji(stc.jours_restants)} ${stc.numero_stc}\n`;
    emailBody += `   🧑 ${stc.nom_salarie} (${stc.code_salarie})\n`;
    emailBody += `   ⏰ ${stc.jours_restants} ${T.jours} (${T.limite}: ${formaterDate(stc.date_limite, langue)})\n\n`;
  });
  emailBody += `${T.cc_message.action}\n\n`;
  emailBody += `${T.cordialement},\n\n${T.signature}\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} | ${T.copie_info} | ${T.ne_pas_repondre}\n`;

  let telegram = `${T.copie_info}\n━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegram += `${T.salutation} *${destinataireCC.prenom ? destinataireCC.prenom + ' ' : ''}${destinataireCC.nom}*,\n\n`;
  telegram += `${T.cc_message.base} ${label} *${destPrincipal.prenom || ''} ${destPrincipal.nom}*.\n\n`;
  telegram += `📊 ${T.total}: *${stats.total_stc}* | ${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;
  stcList.slice(0, 3).forEach((stc, index) => {
    telegram += `${index + 1}. ${getEmoji(stc.jours_restants)} *${stc.numero_stc}*\n`;
    telegram += `   🧑 ${stc.nom_salarie} — ⏰ ${stc.jours_restants} ${T.jours}\n\n`;
  });
  if (stcList.length > 3) telegram += `... et ${stcList.length - 3} autre(s) STC\n\n`;
  telegram += `${T.cc_message.action}\n`;

  return {
    email:    { subject: emailSubject, body: emailBody },
    telegram: { text: telegram, parse_mode: 'Markdown' }
  };
}

// ─── DISPATCH ───
const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messagesPrincipal = genererMessagePrincipal(data);

  results.push({
    json: {
      ...data,
      messages:           messagesPrincipal,
      type_envoi:         'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, langue_utilisee: data.meta.langue_message || 'FRA', date_generation: new Date().toISOString() }
    }
  });

  // CC : SUPERIEUR → copie au salarié
  if (data.type_destinataire === 'SUPERIEUR' && data.salarie?.chat_id) {
    const msgCC = genererMessageCC(data, data.salarie, 'SUPERIEUR');
    results.push({ json: {
      ...data, messages: msgCC, type_envoi: 'CC',
      destinataire_final: data.salarie, cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() }
    }});
  }

  // CC : PDG → copie supérieur + salarié
  if (data.type_destinataire === 'PDG') {
    if (data.superieur?.chat_id) {
      const msgCCSup = genererMessageCC(data, data.superieur, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSup, type_envoi: 'CC',
        destinataire_final: data.superieur, cc_pour_profil: 'SUPERIEUR',
        meta: { ...data.meta, langue_utilisee: data.superieur.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
    if (data.salarie?.chat_id) {
      const msgCCSal = genererMessageCC(data, data.salarie, 'PDG');
      results.push({ json: {
        ...data, messages: msgCCSal, type_envoi: 'CC',
        destinataire_final: data.salarie, cc_pour_profil: 'SALARIE',
        meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() }
      }});
    }
  }
  // BAALLAH, DGA, FARHAT, SALARIE → pas de CC
});

